    // Two-pointer approach starting from both ends
    int leftPointer = 0;
    int rightPointer = height.length - 1;
    int maximumWater = 0;

    while (leftPointer < rightPointer) {
        // Compute water volume for current container
        int currentHeight = Math.min(height[leftPointer], height[rightPointer]);
        int currentWidth = rightPointer - leftPointer;
        int currentWater = currentHeight * currentWidth;
        maximumWater = Math.max(maximumWater, currentWater);

