public void nextPermutation(int[] nums) {
    int length = nums.length;

    // Find the rightmost element that is smaller than the element to its right
    int pivotIndex = length - 2;
    while (pivotIndex >= 0 && nums[pivotIndex] >= nums[pivotIndex + 1]) {
        pivotIndex--;
    }

    if (pivotIndex >= 0) {
        // Find the smallest element larger than the pivot in the suffix
        int swapIndex = length - 1;
        while (nums[swapIndex] <= nums[pivotIndex]) {
            swapIndex--;
        }
        // Swap pivot with that element
        int temp = nums[pivotIndex];
        nums[pivotIndex] = nums[swapIndex];
        nums[swapIndex] = temp;
    }

    // Reverse the suffix to produce the next permutation
    int left = pivotIndex + 1;
    int right = length - 1;
    while (left < right) {
        int temp = nums[left];
        nums[left++] = nums[right];
        nums[right--] = temp;
    }
}

