def longestPalindrome(self, s):
    def expand_from_center(left, right):
        """Expand outward as long as characters match."""
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        # Return the valid palindrome (shrink back one step)
        return s[left + 1:right]

    longest = ''

    for center_index in range(len(s)):
        # Check odd-length palindromes centered at center_index
        odd_palindrome = expand_from_center(center_index, center_index)
        if len(odd_palindrome) > len(longest):
            longest = odd_palindrome

        # Check even-length palindromes centered between center_index and center_index+1
        even_palindrome = expand_from_center(center_index, center_index + 1)
        if len(even_palindrome) > len(longest):
            longest = even_palindrome

    return longest

