void gen(List<String> res, StringBuilder sb, int op, int cl, int n) {
    if (sb.length() == 2 * n) { res.add(sb.toString()); return; }
    if (op < n) { sb.append('('); gen(res, sb, op+1, cl, n); sb.deleteCharAt(sb.length()-1); }
    if (cl < op) { sb.append(')'); gen(res, sb, op, cl+1, n); sb.deleteCharAt(sb.length()-1); }
}

