private void generateHelper(List<String> results, String currentString,
                             int openCount, int closeCount, int maxPairs) {
    // Base case: we have placed all parentheses
    if (currentString.length() == maxPairs * 2) {
        results.add(currentString);
        return;
    }

    // Add opening bracket if we have capacity
    if (openCount < maxPairs) {
        generateHelper(results, currentString + "(", openCount + 1, closeCount, maxPairs);
    }

    // Add closing bracket only if it won't exceed open brackets
    if (closeCount < openCount) {
        generateHelper(results, currentString + ")", openCount, closeCount + 1, maxPairs);
    }
}

