def topKFrequent(self, nums, k):
    from collections import Counter

    # Count frequency of each number
    frequency_map = Counter(nums)

    # Use bucket sort: index represents frequency, value is list of numbers
    buckets = [[] for _ in range(len(nums) + 1)]
    for number, frequency in frequency_map.items():
        buckets[frequency].append(number)

    # Collect top-k elements by iterating from highest frequency bucket
    top_k_elements = []
    for bucket in reversed(buckets):
        for number in bucket:
            top_k_elements.append(number)
            if len(top_k_elements) == k:
                return top_k_elements

    return top_k_elements

def topKFrequent(self, nums, k):
    from collections import Counter
    cnt = Counter(nums)
    buckets = [[] for _ in range(len(nums)+1)]
    for n, f in cnt.items(): buckets[f].append(n)
    return [n for b in reversed(buckets) for n in b][:k]

