    for (int n : nums) count.merge(n, 1, Integer::sum);
    PriorityQueue<Map.Entry<Integer, Integer>> heap =
        new PriorityQueue<>(Comparator.comparingInt(Map.Entry::getValue));
    for (Map.Entry<Integer, Integer> e : count.entrySet()) {
        heap.offer(e);
        if (heap.size() > k) heap.poll();
    }
    return heap.stream().mapToInt(Map.Entry::getKey).toArray();
}

public int[] topKFrequent(int[] nums, int k) {
    HashMap<Integer, Integer> freq = new HashMap<>();
    for (int n : nums) freq.put(n, freq.getOrDefault(n, 0) + 1);
    List<Integer>[] bucket = new List[nums.length + 1];
    for (int key : freq.keySet()) {
        int f = freq.get(key);
        if (bucket[f] == null) bucket[f] = new ArrayList<>();
        bucket[f].add(key);
    }
    int[] res = new int[k];
    int idx = 0;
    for (int i = bucket.length - 1; i >= 0 && idx < k; i--)
        if (bucket[i] != null)
            for (int n : bucket[i]) if (idx < k) res[idx++] = n;
    return res;
}

public int[] topKFrequent(int[] nums, int k) {
    // Count frequency of each number
    Map<Integer, Integer> frequencyMap = new HashMap<>();
    for (int number : nums) {
        frequencyMap.merge(number, 1, Integer::sum);
    }

    // Bucket sort: index = frequency, value = list of numbers with that frequency
    List<Integer>[] frequencyBuckets = new List[nums.length + 1];
    for (Map.Entry<Integer, Integer> entry : frequencyMap.entrySet()) {
        int frequency = entry.getValue();
        if (frequencyBuckets[frequency] == null) {
            frequencyBuckets[frequency] = new ArrayList<>();
        }
        frequencyBuckets[frequency].add(entry.getKey());
    }

    // Collect top-k by scanning from highest frequency
    int[] topKElements = new int[k];
    int resultIndex = 0;
    for (int freq = frequencyBuckets.length - 1; freq >= 0 && resultIndex < k; freq--) {
        if (frequencyBuckets[freq] != null) {
            for (int number : frequencyBuckets[freq]) {
                if (resultIndex < k) topKElements[resultIndex++] = number;
            }
        }
    }
    return topKElements;
}

public int[] topKFrequent(int[] nums, int k) {
