    cnt.forEach((n,f) -> { if (b[f]==null) b[f]=new ArrayList<>(); b[f].add(n); });
    int[] res = new int[k]; int i = 0;
    for (int f = b.length-1; f >= 0 && i < k; f--)
        if (b[f] != null) for (int n : b[f]) if (i < k) res[i++] = n;
