public int subarraySum(int[] nums, int k) {
    // prefixCount maps each prefix sum to how many times it has appeared
    Map<Integer, Integer> prefixCount = new HashMap<>();
    prefixCount.put(0, 1);  // base case: empty prefix

    int runningSum = 0;
    int validSubarrays = 0;

    for (int number : nums) {
        runningSum += number;

        // Check how many previous prefix sums differ by exactly k
        validSubarrays += prefixCount.getOrDefault(runningSum - k, 0);

        // Record this prefix sum
        prefixCount.merge(runningSum, 1, Integer::sum);
    }

    return validSubarrays;
}

