    for (int n : nums) { pre+=n; res+=d.getOrDefault(pre-k,0); d.merge(pre,1,Integer::sum); }
    return res;
}

def lengthOfLongestSubstring(self, s):
    char_index = {}
    left = 0
    best = 0
    for right, ch in enumerate(s):
        if ch in char_index and char_index[ch] >= left:
            left = char_index[ch] + 1
        char_index[ch] = right
        best = max(best, right - left + 1)
    return best

def lengthOfLongestSubstring(self, s):
    seen = {}
    lo = 0
    ans = 0
    for hi, c in enumerate(s):
        if c in seen:
            lo = max(lo, seen[c] + 1)
        seen[c] = hi
        ans = max(ans, hi - lo + 1)
    return ans

def lengthOfLongestSubstring(self, s):
    # Maps each character to the index of its last occurrence
    last_seen_at = {}
    window_start = 0
    longest_length = 0

    for current_index, character in enumerate(s):
        # If character was seen inside the current window, shrink from the left
        if character in last_seen_at and last_seen_at[character] >= window_start:
            window_start = last_seen_at[character] + 1

        last_seen_at[character] = current_index
        current_window_length = current_index - window_start + 1
        longest_length = max(longest_length, current_window_length)

    return longest_length

def lengthOfLongestSubstring(self, s):
    seen, l, res = {}, 0, 0
    for r, c in enumerate(s):
        if c in seen: l = max(l, seen[c]+1)
        seen[c] = r
        res = max(res, r-l+1)
    return res

public int lengthOfLongestSubstring(String s) {
    Map<Character, Integer> charIndex = new HashMap<>();
    int left = 0, best = 0;
    for (int right = 0; right < s.length(); right++) {
        char ch = s.charAt(right);
        if (charIndex.containsKey(ch) && charIndex.get(ch) >= left) {
            left = charIndex.get(ch) + 1;
        }
        charIndex.put(ch, right);
        best = Math.max(best, right - left + 1);
    }
    return best;
}

public int lengthOfLongestSubstring(String s) {
    HashMap<Character, Integer> seen = new HashMap<>();
    int lo = 0, ans = 0;
    for (int hi = 0; hi < s.length(); hi++) {
        char c = s.charAt(hi);
        if (seen.containsKey(c)) lo = Math.max(lo, seen.get(c) + 1);
        seen.put(c, hi);
        ans = Math.max(ans, hi - lo + 1);
    }
    return ans;
}

public int lengthOfLongestSubstring(String s) {
    // Track the most recent index of each character
    Map<Character, Integer> lastSeenAt = new HashMap<>();
    int windowStart = 0;
    int longestLength = 0;

    for (int currentIndex = 0; currentIndex < s.length(); currentIndex++) {
        char character = s.charAt(currentIndex);

        // Shrink the window if this character is already inside it
        if (lastSeenAt.containsKey(character) && lastSeenAt.get(character) >= windowStart) {
            windowStart = lastSeenAt.get(character) + 1;
        }

        lastSeenAt.put(character, currentIndex);
        longestLength = Math.max(longestLength, currentIndex - windowStart + 1);
    }

    return longestLength;
}

public int lengthOfLongestSubstring(String s) {
    Map<Character,Integer> seen = new HashMap<>();
    int l = 0, res = 0;
    for (int r = 0; r < s.length(); r++) {
        char c = s.charAt(r);
        if (seen.containsKey(c)) l = Math.max(l, seen.get(c)+1);
        seen.put(c, r); res = Math.max(res, r-l+1);
    }
    return res;
}
